command:
mkdir -p space && printf 'metrics:
  - {id: m1, dimension: performance, reporting_window: 7d}
' > space/metrics.yaml && printf 'dimensions: {performance: {enabled: true}}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --config space/config.yaml 2>out.txt && grep -q 'window=7d' out.txt && echo ok 1>&2
